import{_ as o,o as n,c as t,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"71. Supporting Professional Development","description":"","frontmatter":{"title":"71. Supporting Professional Development","eba":"Biomedical Engineers 2025-2028","topics":["leave"]},"headers":[],"relativePath":"ebas/biomedical-engineers/education-pd/71-supporting-professional-development.md","filePath":"ebas/biomedical-engineers/education-pd/71-supporting-professional-development.md"}'),s={name:"ebas/biomedical-engineers/education-pd/71-supporting-professional-development.md"};function i(l,e,p,r,m,c){return n(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="_71-supporting-professional-development" tabindex="-1">71. Supporting Professional Development <a class="header-anchor" href="#_71-supporting-professional-development" aria-label="Permalink to &quot;71. Supporting Professional Development&quot;">​</a></h1><p><strong>71.1</strong> Employers will ensure Employees have equitable access to voluntary in-service training or professional development opportunities.</p><p><strong>71.2</strong> Employers will communicate such upcoming training or professional development opportunities to Employees through established channels, such as email notifications, intranet announcements, or team meetings.</p><p><strong>71.3</strong> If an application is made to access Professional Development Leave under <a href="/eba/ebas/biomedical-engineers/education-pd/72-professional-development-leave.html">clause 72</a> (or other leave under the Agreement), subject to the specific clause, approval of leave will not be unreasonably withheld.</p><p><strong>71.4</strong> Professional Development Allowance This subclause does not apply to casual Employees.</p><p><strong>(a)</strong> Full-time Employees will be entitled to an annual professional development allowance in accordance with the following table: Payment Amount Eligibility Date FFPPOOA commencement of the $1500.00 Agreement</p><p>$1545.00 FFPPOOA 1 August 2025</p><p>$1591.35 FFPPOOA 1 August 2026</p><p>FFPPOOA 1 August 2027 and each 1 $1639.09 August thereafter</p><p><strong>(b)</strong> Additional payment Employees who were employed by an Employer on 13 September 2023 and are Employees on commencement of the Agreement are entitled to a once off $500 payment in recognition of the professional development allowance that was not received in 2023.</p><p><strong>(c)</strong> The amounts at subclause 71.4(a) and (b) will be paid pro rata for part-time Employees.</p><p><strong>(d)</strong> The professional development allowance is additional to any other allowance or entitlement within this Agreement.</p>',12)])])}const g=o(s,[["render",i]]);export{u as __pageData,g as default};
